package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVFormat.Predefined;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVFormatTest {

    @Test
    void testValueOf_withValidPredefinedFormat() {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat expectedFormat = CSVFormat.DEFAULT;
            Predefined mockedPredefinedInstance = Mockito.mock(Predefined.class);
            Mockito.when(CSVFormat.Predefined.valueOf("DEFAULT")).thenReturn(mockedPredefinedInstance);
            Mockito.when(mockedPredefinedInstance.getFormat()).thenReturn(expectedFormat);

            CSVFormat actualFormat = CSVFormat.valueOf("DEFAULT");

            assertSame(expectedFormat, actualFormat);
            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf("DEFAULT"));
            Mockito.verify(mockedPredefinedInstance).getFormat();
        }
    }

    @Test
    void testValueOf_withAnotherValidPredefinedFormat() {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat expectedFormat = CSVFormat.RFC4180;
            Predefined mockedPredefinedInstance = Mockito.mock(Predefined.class);
            Mockito.when(CSVFormat.Predefined.valueOf("RFC4180")).thenReturn(mockedPredefinedInstance);
            Mockito.when(mockedPredefinedInstance.getFormat()).thenReturn(expectedFormat);

            CSVFormat actualFormat = CSVFormat.valueOf("RFC4180");

            assertSame(expectedFormat, actualFormat);
            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf("RFC4180"));
            Mockito.verify(mockedPredefinedInstance).getFormat();
        }
    }

    @Test
    void testValueOf_withNullFormat_shouldThrowNullPointerException() {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf(null)).thenThrow(NullPointerException.class);

            assertThrows(NullPointerException.class, () -> CSVFormat.valueOf(null));

            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf(null));
        }
    }

    @Test
    void testValueOf_withInvalidFormat_shouldThrowIllegalArgumentException() {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            String invalidFormat = "INVALID_FORMAT";
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf(invalidFormat))
                    .thenThrow(IllegalArgumentException.class);

            assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf(invalidFormat));

            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf(invalidFormat));
        }
    }
}
